def solve(s: str, k: int) -> str:
    res = []
    for c in s:
        if c == '*':
            if res:
                res.pop()
        elif c == '#':
            res += res
        elif c == '%':
            res = res[::-1]
        else:
            res.append(c)
    if k < len(res):
        return res[k]
    else:
        return '.'
